"use client";

import { Check } from "lucide-react";
import {
  motion,
  AnimatePresence,
  useMotionValue,
  useSpring,
  useReducedMotion,
} from "motion/react";
import { useState, useRef, useEffect } from "react";
import type { FC, ChangeEvent, KeyboardEvent, MouseEvent } from "react";
import { BiSolidPencil } from "react-icons/bi";

import { cn } from "@/lib/utils";

interface EditableChipProps {
  defaultLabel?: string;
  showThemeToggle?: boolean;
  onChange?: (value: string) => void;
}

const getCaretIndex = (target: HTMLInputElement) => {
  const start = target.selectionStart ?? 0;
  const end = target.selectionEnd ?? 0;
  if (start === end) return start;
  return target.selectionDirection === "backward" ? start : end;
};

export const EditableChip: FC<EditableChipProps> = ({
  defaultLabel = "Watchlist",
  onChange,
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [label, setLabel] = useState<string>(defaultLabel);

  const inputRef = useRef<HTMLInputElement>(null);
  const measureRef = useRef<HTMLSpanElement>(null);

  const caretX = useMotionValue(0);
  const caretOpacity = useMotionValue(0);
  const prefersReducedMotion = useReducedMotion();
  const springCaretX = useSpring(
    caretX,
    prefersReducedMotion
      ? { damping: 100, mass: 0.1, stiffness: 10_000 }
      : { damping: 30, mass: 0.5, stiffness: 500 },
  );

  const updateCaret = (target: HTMLInputElement) => {
    const measureSpan = measureRef.current;
    if (!measureSpan) return;

    const start = target.selectionStart ?? 0;
    const end = target.selectionEnd ?? 0;
    const hasSelection = start !== end;
    const caretIndex = getCaretIndex(target);
    const textBefore = target.value.slice(0, caretIndex);

    const styles = window.getComputedStyle(target);
    measureSpan.style.font = `${styles.fontStyle} ${styles.fontWeight} ${styles.fontSize} ${styles.fontFamily}`;
    measureSpan.style.letterSpacing = styles.letterSpacing;
    measureSpan.textContent = textBefore;

    const paddingLeft = Number.parseFloat(styles.paddingLeft) || 0;
    const paddingRight = Number.parseFloat(styles.paddingRight) || 0;
    const textWidth =
      textBefore.length > 0 ? measureSpan.offsetWidth + paddingLeft : paddingLeft - 1;

    const maxScroll = Math.max(0, target.scrollWidth - target.clientWidth);
    const visibleRight = target.scrollLeft + target.clientWidth - paddingRight;
    const visibleLeft = target.scrollLeft + paddingLeft;

    if (textWidth > visibleRight) {
      target.scrollLeft = Math.min(
        textWidth - target.clientWidth + paddingRight,
        maxScroll,
      );
    } else if (textWidth < visibleLeft) {
      target.scrollLeft = Math.max(0, textWidth - paddingLeft);
    }

    const caretPosition = textWidth - target.scrollLeft;
    const maxX = target.clientWidth - paddingRight;
    const minX = paddingLeft - 1;
    const isVisible = caretPosition >= minX && caretPosition <= maxX + 1;

    caretX.set(Math.min(caretPosition, maxX));
    caretOpacity.set(!isVisible || hasSelection ? 0 : 1);
  };

  const updateCaretRef = useRef(updateCaret);
  updateCaretRef.current = updateCaret;

  useEffect(() => {
    const input = inputRef.current;
    if (!input || !isEditing) return;

    const handleSelectionChange = () => {
      if (document.activeElement !== input) return;
      requestAnimationFrame(() => {
        if (document.activeElement === input) {
          updateCaretRef.current(input);
        }
      });
    };

    document.addEventListener("selectionchange", handleSelectionChange);
    input.addEventListener("input", () =>
      requestAnimationFrame(() => updateCaretRef.current(input)),
    );

    requestAnimationFrame(() => {
      input.focus();
      input.select();
      updateCaretRef.current(input);
    });

    return () => {
      document.removeEventListener("selectionchange", handleSelectionChange);
    };
  }, [isEditing]);

  const handleSave = (e: MouseEvent | KeyboardEvent) => {
    e.stopPropagation();
    const finalValue = label.trim() === "" ? "Untitled" : label;
    setLabel(finalValue);
    setIsEditing(false);
    onChange?.(finalValue);
  };

  const handleEdit = () => {
    setIsEditing(true);
  };

  return (
    <motion.div layout>
      <div
        className={cn(
          "relative flex cursor-pointer items-center justify-center gap-2 overflow-hidden rounded-full border border-zinc-200 py-1 pr-1 transition-all duration-300 ease-in-out select-none dark:border-zinc-700 dark:bg-zinc-900",
          isEditing && "gap-8 ring-2 ring-black dark:ring-white",
        )}
      >
        <div
          className="relative grid grid-cols-1 flex-1"
          style={{ caretColor: "transparent" }}
        >
          <input
            ref={inputRef}
            type="text"
            value={label}
            readOnly={!isEditing}
            onChange={(e: ChangeEvent<HTMLInputElement>) =>
              setLabel(e.target.value)
            }
            onKeyDown={(e: KeyboardEvent<HTMLInputElement>) =>
              e.key === "Enter" && handleSave(e)
            }
            onClick={(e: MouseEvent) => e.stopPropagation()}
            className={cn(
              "col-start-1 col-end-2 row-start-1 row-end-2 ml-4 w-32 border-none bg-transparent text-lg font-medium text-[#262626] capitalize outline-none selection:bg-[#B6B6B6] dark:text-zinc-100 dark:selection:bg-zinc-700",
            )}
          />
          <span
            ref={measureRef}
            aria-hidden
            className="pointer-events-none invisible absolute top-0 left-0 whitespace-pre"
          />
          {isEditing && (
            <motion.div
              className="pointer-events-none col-start-1 col-end-2 row-start-1 row-end-2 h-[0.9em] w-0.5 self-center rounded-full bg-black dark:bg-white"
              style={{ opacity: caretOpacity, x: springCaretX }}
            />
          )}
        </div>

        <AnimatePresence mode="popLayout">
          {isEditing ? (
            <motion.button
              key="done"
              initial={{ filter: "blur(4px)", opacity: 0, scale: 0 }}
              animate={{ filter: "blur(0px)", opacity: 1, scale: 1 }}
              exit={{ filter: "blur(4px)", opacity: 0, scale: 0 }}
              layout="position"
              onClick={handleSave}
              transition={{
                bounce: 0,
                duration: 0.4,
                type: "spring",
              }}
              className="rounded-full bg-black p-1 text-white transition-colors dark:bg-zinc-100 dark:text-zinc-950"
            >
              <Check size={26} />
            </motion.button>
          ) : (
            <motion.button
              key="edit"
              initial={{ filter: "blur(4px)", opacity: 0, scale: 0 }}
              animate={{ filter: "blur(0px)", opacity: 1, scale: 1 }}
              exit={{ filter: "blur(4px)", opacity: 0, scale: 0 }}
              layout="position"
              onClick={handleEdit}
              transition={{
                bounce: 0,
                duration: 0.4,
                type: "spring",
              }}
              className="rounded-full bg-[#F0EFF6] p-1 text-[#696871] transition-colors dark:bg-zinc-800 dark:text-zinc-400 hover:dark:bg-zinc-700"
            >
              <BiSolidPencil size={26} />
            </motion.button>
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
};

